content.text:
#!/usr/bin/env tsx
// remember.ts — Write a memory to the brain (markdown + index)
// Usage: tsx scripts/remember.ts --type person --file people/nik.md --section "Key Facts" --content "Prefers Deno over Node" --tags "nik,coding"
//        tsx scripts/remember.ts --type daily --content "Nik seemed energized today" --tags "mood"
//        tsx scripts/remember.ts --type projects --project dots --org nikbrunner --content "Refactored project dir structure" --tags "maintenance"

import { join } from "node:path";
import { parseArgs } from "node:util";
import { execFileSync } from "node:child_process";
import { BrainStore } from "./store.js";
import { appendToSection, dailyNotePath, today, tagsToString, extractTitle } from "./markdown.js";
import type { BrainFileType } from "./types.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");

interface RememberArgs {
  type: BrainFileType;
  file?: string;
  section?: string;
  content: string;
  tags: string;
  project?: string;
  org?: string;
  commit?: boolean;
}

function parseCliArgs(): RememberArgs {
  const { values } = parseArgs({
    args: process.argv.slice(2),
    options: {
      type: { type: "string", default: "daily" },
      file: { type: "string" },
      section: { type: "string", default: "Key Facts" },
      content: { type: "string" },
      tags: { type: "string", default: "" },
      project: { type: "string" },
      org: { type: "string", default: "nikbrunner" },
      commit: { type: "boolean", default: true },
    },
    allowPositionals: true,
  });

  // Support positional content argument
  const content = values.content || (values as Record<string, unknown>)._[0] as string;
  if (!content) {
    console.error("Error: --content required (or pass as positional argument)");
    process.exit(1);
  }

  return {
    type: (values.type || "daily") as BrainFileType,
    file: values.file as string | undefined,
    section: (values.section || "Key Facts") as string,
    content,
    tags: (values.tags || "") as string,
    project: values.project as string | undefined,
    org: (values.org || "nikbrunner") as string,
    commit: values.commit as boolean | undefined,
  };
}

async function remember(args: RememberArgs): Promise<void> {
  const store = new BrainStore(DB_PATH);

  // Determine the target file
  let filePath: string;
  if (args.file) {
    filePath = args.file;
  } else if (args.type === "daily") {
    filePath = dailyNotePath(today());
  } else if (args.type === "projects" && args.project) {
    filePath = `projects/${args.org}/${args.project}/${today()}.md`;
  } else {
    const slug = args.content.slice(0, 40).toLowerCase().replace(/[^a-z0-9]+/g, "-");
    filePath = `${args.type}/${slug}.md`;
  }

  const tags = args.tags.split(",").map(t => t.trim()).filter(Boolean);

  // Write to markdown
  const updatedFile = appendToSection(
    filePath,
    args.section,
    args.content,
    {
      type: args.type,
      tags,
      updated: today(),
    }
  );

  // Update index
  const title = extractTitle(updatedFile.content);
  store.upsertFile({
    path: updatedFile.path,
    checksum: updatedFile.checksum,
    type: updatedFile.frontmatter.type || args.type,
    tags: tagsToString(updatedFile.frontmatter.tags || tags),
    title,
    content: updatedFile.content,
    updated: updatedFile.frontmatter.updated || today(),
    indexed_at: new Date().toISOString(),
  });

  const fileRel = updatedFile.path;
  console.log(`Remembered in ${fileRel}: ${args.content}`);
  store.close();

  // Auto-commit the change
  if (args.commit) {
    try {
      execFileSync("git", ["add", `brain/${fileRel}`], { cwd: ROOT_DIR, stdio: "pipe" });
      execFileSync("git", ["diff", "--cached", "--quiet"], { cwd: ROOT_DIR, stdio: "pipe" });
      // exit 0 = nothing new staged (duplicate or no-op) — skip commit
    } catch {
      // exit non-zero = changes staged — commit
      const desc = args.content.slice(0, 60).replace(/[^\w\s-/]/g, "").trim();
      const msg = `feat(brain): ${desc}`;
      execFileSync("git", ["commit", "-m", msg], { cwd: ROOT_DIR, stdio: "pipe" });
      console.log(`Committed: ${msg}`);
    }
  }
}

// Allow programmatic use
export async function rememberMemory(
  type: BrainFileType,
  content: string,
  options?: { file?: string; section?: string; tags?: string[]; project?: string; org?: string; commit?: boolean }
): Promise<string> {
  const filePath = options?.file
    || (type === "daily" ? dailyNotePath(today())
    : (type === "projects" && options?.project)
      ? `projects/${options.org || "nikbrunner"}/${options.project}/${today()}.md`
      : `${type}/${content.slice(0, 40).toLowerCase().replace(/[^a-z0-9]+/g, "-")}.md`);
  const section = options?.section || "Key Facts";
  const tags = options?.tags || [];

  const updatedFile = appendToSection(filePath, section, content, { type, tags, updated: today() });

  const store = new BrainStore(DB_PATH);
  store.upsertFile({
    path: updatedFile.path,
    checksum: updatedFile.checksum,
    type,
    tags: tagsToString(tags),
    title: extractTitle(updatedFile.content),
    content: updatedFile.content,
    updated: today(),
    indexed_at: new Date().toISOString(),
  });
  store.close();

  return updatedFile.path;
}

// CLI entry point
if (import.meta.url === `file://${process.argv[1]}` || process.argv[1]?.endsWith("/remember.ts")) {
  const args = parseCliArgs();
  remember(args).catch(err => {
    console.error("remember failed:", err);
    process.exit(1);
  });
}

