// git.ts — Git helpers for the third-brain
// Shared between Pi extension and Claude Code hooks

import { execFileSync } from "node:child_process";

/**
 * Stage a brain file and commit if there are changes.
 *
 * @param rootDir  Git repo root (e.g. third-brain dir)
 * @param fileRel  Path relative to brain/ directory
 * @param message  Commit message (type is always `feat(brain):`)
 * @returns true if committed, false if nothing to stage
 */
export function commitFile(rootDir: string, fileRel: string, message: string): boolean {
  try {
    execFileSync("git", ["add", `brain/${fileRel}`], { cwd: rootDir, stdio: "pipe" });
    execFileSync("git", ["diff", "--cached", "--quiet"], { cwd: rootDir, stdio: "pipe" });
    // exit 0 = nothing staged — no-op
    return false;
  } catch {
    // exit non-zero = changes staged — commit
    const desc = message.slice(0, 60).replace(/\s+/g, " ").trim();
    const msg = `feat(brain): ${desc}`;
    execFileSync("git", ["commit", "-m", msg], { cwd: rootDir, stdio: "pipe" });
    return true;
  }
}

